/// <summary>
/// A backup parse/serialize/validate failure. Mirrors `hw_backup::BackupError`.
/// </summary>
internal class BackupException: UniffiException {
    BackupException() : base() {}
    BackupException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    
    public class Parse : BackupException {
        // Members
        public string @message;

        // Constructor
        public Parse(
                string @message) : base(
                "@message" + "=" + @message) {

            this.@message = @message;
        }
    }
    
    
    public class Serialize : BackupException {
        // Members
        public string @message;

        // Constructor
        public Serialize(
                string @message) : base(
                "@message" + "=" + @message) {

            this.@message = @message;
        }
    }
    
    
    public class Invalid : BackupException {
        // Members
        public string @message;

        // Constructor
        public Invalid(
                string @message) : base(
                "@message" + "=" + @message) {

            this.@message = @message;
        }
    }
    

    
}

class FfiConverterTypeBackupError : FfiConverterRustBuffer<BackupException>, CallStatusErrorHandler<BackupException> {
    public static FfiConverterTypeBackupError INSTANCE = new FfiConverterTypeBackupError();

    public override BackupException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new BackupException.Parse(
                    FfiConverterString.INSTANCE.Read(stream));
            case 2:
                return new BackupException.Serialize(
                    FfiConverterString.INSTANCE.Read(stream));
            case 3:
                return new BackupException.Invalid(
                    FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeBackupError.Read()", value));
        }
    }

    public override int AllocationSize(BackupException value) {
        switch (value) {

            case BackupException.Parse variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);

            case BackupException.Serialize variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);

            case BackupException.Invalid variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeBackupError.AllocationSize()", value));
        }
    }

    public override void Write(BackupException value, BigEndianStream stream) {
        switch (value) {
            case BackupException.Parse variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            case BackupException.Serialize variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            case BackupException.Invalid variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeBackupError.Write()", value));
        }
    }
}





/// <summary>
/// The request body the platform must send. Mirrors `hw_net::Body`.
/// </summary>
internal record Body {
    
    public record Empty: Body {}
    
    
    public record Bytes (
        string @contentType,
        byte[] @data
    ) : Body {}
    
    public record Multipart (
        string @boundary,
        List<HwPart> @parts
    ) : Body {}
    
    public record FileStream (
        string @path,
        string @contentType
    ) : Body {}
    

    
}

class FfiConverterTypeBody : FfiConverterRustBuffer<Body>{
    public static FfiConverterRustBuffer<Body> INSTANCE = new FfiConverterTypeBody();

    public override Body Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new Body.Empty(
                );
            case 2:
                return new Body.Bytes(
                    FfiConverterString.INSTANCE.Read(stream),
                    FfiConverterByteArray.INSTANCE.Read(stream)
                );
            case 3:
                return new Body.Multipart(
                    FfiConverterString.INSTANCE.Read(stream),
                    FfiConverterSequenceTypeHwPart.INSTANCE.Read(stream)
                );
            case 4:
                return new Body.FileStream(
                    FfiConverterString.INSTANCE.Read(stream),
                    FfiConverterString.INSTANCE.Read(stream)
                );
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeBody.Read()", value));
        }
    }

    public override int AllocationSize(Body value) {
        switch (value) {
            case Body.Empty variant_value:
                return 4;
            case Body.Bytes variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@contentType)
                    + FfiConverterByteArray.INSTANCE.AllocationSize(variant_value.@data);
            case Body.Multipart variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@boundary)
                    + FfiConverterSequenceTypeHwPart.INSTANCE.AllocationSize(variant_value.@parts);
            case Body.FileStream variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@path)
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@contentType);
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeBody.AllocationSize()", value));
        }
    }

    public override void Write(Body value, BigEndianStream stream) {
        switch (value) {
            case Body.Empty variant_value:
                stream.WriteInt(1);
                break;
            case Body.Bytes variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.@contentType, stream);
                FfiConverterByteArray.INSTANCE.Write(variant_value.@data, stream);
                break;
            case Body.Multipart variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@boundary, stream);
                FfiConverterSequenceTypeHwPart.INSTANCE.Write(variant_value.@parts, stream);
                break;
            case Body.FileStream variant_value:
                stream.WriteInt(4);
                FfiConverterString.INSTANCE.Write(variant_value.@path, stream);
                FfiConverterString.INSTANCE.Write(variant_value.@contentType, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeBody.Write()", value));
        }
    }
}







