/// <summary>
/// Normalized transcription failures. Mirrors `hw_net::TranscriptionError` as a
/// UniFFI error enum. `Display` is implemented by hand (matching the leaf's
/// `thiserror` messages) so hw-core needs no extra dependency.
/// </summary>
internal class HwTranscriptionException: UniffiException {
    HwTranscriptionException() : base() {}
    HwTranscriptionException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    public class Unauthorized : HwTranscriptionException {
        public Unauthorized() : base() {}
    }
    
    
    public class QuotaExceeded : HwTranscriptionException {
        public QuotaExceeded() : base() {}
    }
    
    
    public class FileTooLarge : HwTranscriptionException {
        public FileTooLarge() : base() {}
    }
    
    
    
    public class RateLimited : HwTranscriptionException {
        // Members
        public ulong? @retryAfterSecs;

        // Constructor
        public RateLimited(
                ulong? @retryAfterSecs) : base(
                "@retryAfterSecs" + "=" + @retryAfterSecs) {

            this.@retryAfterSecs = @retryAfterSecs;
        }
    }
    
    
    public class ProviderUnavailable : HwTranscriptionException {
        // Members
        public ushort @status;

        // Constructor
        public ProviderUnavailable(
                ushort @status) : base(
                "@status" + "=" + @status) {

            this.@status = @status;
        }
    }
    
    public class NoSpeech : HwTranscriptionException {
        public NoSpeech() : base() {}
    }
    
    
    
    public class BadRequest : HwTranscriptionException {
        // Members
