class FfiConverterTypeHwTranscriptionError : FfiConverterRustBuffer<HwTranscriptionException>, CallStatusErrorHandler<HwTranscriptionException> {
    public static FfiConverterTypeHwTranscriptionError INSTANCE = new FfiConverterTypeHwTranscriptionError();

    public override HwTranscriptionException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new HwTranscriptionException.Unauthorized();
            case 2:
                return new HwTranscriptionException.QuotaExceeded();
            case 3:
                return new HwTranscriptionException.FileTooLarge();
            case 4:
                return new HwTranscriptionException.RateLimited(
                    FfiConverterOptionalUInt64.INSTANCE.Read(stream));
            case 5:
                return new HwTranscriptionException.ProviderUnavailable(
                    FfiConverterUInt16.INSTANCE.Read(stream));
            case 6:
                return new HwTranscriptionException.NoSpeech();
            case 7:
                return new HwTranscriptionException.BadRequest(
                    FfiConverterUInt16.INSTANCE.Read(stream),
                    FfiConverterString.INSTANCE.Read(stream));
            case 8:
                return new HwTranscriptionException.Parse(
                    FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeHwTranscriptionError.Read()", value));
        }
    }

    public override int AllocationSize(HwTranscriptionException value) {
        switch (value) {

            case HwTranscriptionException.Unauthorized variant_value:
                return 4;

            case HwTranscriptionException.QuotaExceeded variant_value:
                return 4;

            case HwTranscriptionException.FileTooLarge variant_value:
                return 4;

            case HwTranscriptionException.RateLimited variant_value:
                return 4
                    + FfiConverterOptionalUInt64.INSTANCE.AllocationSize(variant_value.@retryAfterSecs);

            case HwTranscriptionException.ProviderUnavailable variant_value:
                return 4
                    + FfiConverterUInt16.INSTANCE.AllocationSize(variant_value.@status);

            case HwTranscriptionException.NoSpeech variant_value:
                return 4;

            case HwTranscriptionException.BadRequest variant_value:
                return 4
                    + FfiConverterUInt16.INSTANCE.AllocationSize(variant_value.@status)
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);

            case HwTranscriptionException.Parse variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeHwTranscriptionError.AllocationSize()", value));
        }
    }

    public override void Write(HwTranscriptionException value, BigEndianStream stream) {
        switch (value) {
            case HwTranscriptionException.Unauthorized variant_value:
                stream.WriteInt(1);
                break;
            case HwTranscriptionException.QuotaExceeded variant_value:
                stream.WriteInt(2);
                break;
            case HwTranscriptionException.FileTooLarge variant_value:
                stream.WriteInt(3);
                break;
            case HwTranscriptionException.RateLimited variant_value:
                stream.WriteInt(4);
                FfiConverterOptionalUInt64.INSTANCE.Write(variant_value.@retryAfterSecs, stream);
                break;
            case HwTranscriptionException.ProviderUnavailable variant_value:
                stream.WriteInt(5);
                FfiConverterUInt16.INSTANCE.Write(variant_value.@status, stream);
                break;
            case HwTranscriptionException.NoSpeech variant_value:
                stream.WriteInt(6);
                break;
            case HwTranscriptionException.BadRequest variant_value:
                stream.WriteInt(7);
                FfiConverterUInt16.INSTANCE.Write(variant_value.@status, stream);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            case HwTranscriptionException.Parse variant_value:
                stream.WriteInt(8);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeHwTranscriptionError.Write()", value));
        }
    }
}





